{
  "name": "opslabs-webcontainer-node-hello",
  "version": "1.0.0",
  "type": "module",
  "private": true,
  "description": "opslabs web-container demo: fix the greeting handler",
  "dependencies": {}
}

// opslabs 场景:修复下面这个 handler
//
// 目标:接收一个 name 字符串,返回 { greeting: `hello ${name}` }
// 跑 check 的时候,check.mjs 会 import 这个 default export,
// 拼一个 name=world 进去比对结果。
//
// 现在故意有 bug,自己改过来。

export default function greet(name) {
  // BUG: 字段名拼错了,check 期待的是 greeting,不是 greet
  return { greet: 'hello ' + name }
}

// opslabs web-container 判题脚本
//
// 约定:
//   - 通过时退出码 0,并在 stdout 打印 'OK'(跟 sandbox 模式对齐)
//   - 失败时退出码 1,把期望/实际值印到 stderr
//   - 其它类型错误(import 失败等)退出码 2
//
// Runner 会读 process.exitCode 当成 ClientCheckResult.exitCode 上报后端。

import greet from './handler.js'

try {
  const out = greet('world')
  const expected = { greeting: 'hello world' }

  if (!out || typeof out !== 'object') {
    console.error('handler 没返回对象,拿到:', out)
    process.exit(1)
  }
  if (out.greeting !== expected.greeting) {
    console.error('字段不对 —— 期待 greeting="' + expected.greeting + '",拿到:', JSON.stringify(out))
    process.exit(1)
  }
  console.log('OK')
  process.exit(0)
} catch (e) {
  console.error('handler 抛异常:', e && e.stack || e)
  process.exit(2)
}
